mapper.update:
UPDATE

SET is_deleted = 0, nickname = #{nickname}, password = #{password}
WHERE id = #{id}

mapper.select:
SELECT A.user_id id,B.nickname,B.phone, A.create_time AS createTime,B.email ,B.account,B.pinyin,A.status,A.tenant_id tenantId FROM md_user_org A LEFT JOIN md_user B ON A.user_id=B.id WHERE A.tenant_id=#{tenantId}
AND A.org_id = #{orgId}
AND (( B.phone like concat('%',#{keyword},'%')) OR ( B.email like concat('%',#{keyword},'%')) OR (B.account LIKE CONCAT('%',#{keyword},'%')) OR ((B.nickname like LOWER(concat('%',#{keyword},'%')) OR B.nickname like UPPER(concat('%',#{keyword},'%')))) OR ((B.pinyin like LOWER(concat('%',#{keyword},'%')) OR B.pinyin like UPPER(concat('%',#{keyword},'%')))) OR ((B.pinyins like LOWER(concat('%',#{keyword},'%')) OR B.pinyins like UPPER(concat('%',#{keyword},'%')))))
AND ((BINARY B.account like concat('%',#{account},'%')))
AND A.status=#{userState}
GROUP BY A.user_id ORDER BY A.create_time DESC

SELECT mg.name as orgName, mg.id as orgId, moe.custom_id as customId
FROM md_org
mg
 LEFT JOIN md_user_org rg ON mg.id = rg.org_id
 LEFT JOIN md_org_external moe ON mg.id = moe.org_id
WHERE rg.user_id=#{id}

    AND rg.org_id = #{orgId}


    AND rg.tenant_id = #{tenantId}

GROUP BY mg.id

SELECT mu.id AS id, mu.nickname AS nickname, mu.phone AS phone, mu.create_time AS createTime, mu.email AS email, r.id AS roleIdList, r.name AS roleNameList FROM md_user mu LEFT JOIN md_user_org muo ON muo.user_id = mu.id LEFT JOIN md_user_tenant_role mr ON muo.user_id = mr.user_id AND mr.app_id = #{appId} AND mr.tenant_id = #{tenantId} LEFT JOIN md_role r ON mr.role_id = r.id WHERE muo.tenant_id = #{tenantId}
AND muo.org_id = #{orgId}
AND (BINARY mu.phone like concat('%',#{phone},'%'))
AND (mu.nickname like LOWER(concat('%',#{name},'%')) OR mu.nickname like UPPER(concat('%',#{name},'%')))
ORDER BY muo.create_time DESC

SELECT mu.id AS id, muo.org_id AS orgId, mu.nickname AS name,mu.phone AS phone,mu.email AS email FROM md_user mu LEFT JOIN md_user_org muo ON muo.user_id = mu.id where muo.tenant_id = #{tenantId}
AND muo.org_id = #{orgId}
AND ((BINARY mu.phone like concat('%',#{keyword},'%')) OR (BINARY mu.email like concat('%',#{keyword},'%')) OR (BINARY mu.nickname like LOWER(concat('%',#{keyword},'%')) OR mu.nickname like UPPER(concat('%',#{keyword},'%'))))
AND mu.is_deleted = 0 GROUP BY mu.id ORDER BY muo.create_time desc

SELECT mu.id, mu.phone, mu.nickname, mu.email, mu.account, GROUP_CONCAT(muo.org_id SEPARATOR ',') AS logo
FROM md_user mu
    JOIN md_user_org muo ON muo.user_id = mu.id
WHERE mu.is_deleted = 0
  AND muo.tenant_id = #{tenantId}

    AND mu.id = #{key}


    AND mu.phone = #{key}


    AND mu.email = #{key}
